def custom_fizzbuzz(n, divisors):
    """
    Prints a FizzBuzz sequence up to n, using custom divisors.

    Args:
        n (int): The upper limit (inclusive) for the sequence.
        divisors (dict): A dictionary where keys are divisors (int) 
                          and values are the corresponding output strings (str).
    """
    for i in range(1, n + 1):
        output = ""
        for divisor, word in divisors.items():
            if i % divisor == 0:
                output += word

        if output:
            print(output)
        else:
            print(i)
